"use client"

import * as React from "react"
import {
  Bold,
  Code,
  Heading1,
  Heading2,
  Heading3,
  Italic,
  Link2,
  List,
  ListChecks,
  ListOrdered,
  Minus,
  Quote,
  SquareCode,
  Strikethrough,
  Check,
} from "lucide-react"

import {
  activeBlockType,
  applyInputRule,
  collapsedSelection,
  deleteBackward,
  deleteSelection,
  insertText,
  isMarkActive,
  normalizeSelection,
  parseMarkdown,
  pasteMarkdown,
  plainTextFromInlines,
  selectionIsCollapsed,
  serializeMarkdown,
  setBlockType,
  setLink,
  splitBlock,
  toggleMark,
  toggleTaskChecked,
  type BlockNode,
  type EditorDoc,
  type EditorPath,
  type EditorSelection,
  type EditorState,
  type InlineNode,
  type MarkType,
} from "../lib/df-editor"
import { cn } from "../lib/utils"
import { Button } from "./df-button"

export type EditorToolbarMode = "static" | "floating" | "both" | "none"

export type EditorProps = {
  value: string
  onChange?: (markdown: string) => void
  placeholder?: string
  readOnly?: boolean
  /** CSS value applied to `--df-editor-min-height`. */
  minHeight?: string
  toolbar?: EditorToolbarMode
  autoFocus?: boolean
  className?: string
  "aria-label"?: string
}

type FloatingPos = { top: number; left: number }

const SETTLE_MS = 160

function pathKey(path: EditorPath): string {
  return path.join(".")
}

function parsePathKey(value: string | null | undefined): EditorPath | null {
  if (!value) return null
  const parts = value.split(".").map((part) => Number.parseInt(part, 10))
  if (parts.some((part) => !Number.isFinite(part))) return null
  return parts
}

function findEditableAncestor(node: Node | null, root: HTMLElement): HTMLElement | null {
  let current: Node | null = node
  while (current && current !== root) {
    if (current instanceof HTMLElement && current.dataset.dfPath != null) {
      return current
    }
    current = current.parentNode
  }
  return null
}

function offsetInEditable(editable: HTMLElement, targetNode: Node, targetOffset: number): number {
  const walker = document.createTreeWalker(editable, NodeFilter.SHOW_TEXT)
  let total = 0
  let textNode = walker.nextNode()
  while (textNode) {
    const value = textNode.textContent ?? ""
    const isZwspOnly = value === "\u200b"
    if (textNode === targetNode) {
      if (isZwspOnly) return total
      return total + Math.min(targetOffset, value.length)
    }
    if (!isZwspOnly) total += value.length
    textNode = walker.nextNode()
  }
  return total
}

function readDomSelection(root: HTMLElement): EditorSelection | null {
  const sel = window.getSelection()
  if (!sel || sel.rangeCount === 0) return null
  const range = sel.getRangeAt(0)
  if (!root.contains(range.startContainer) || !root.contains(range.endContainer)) {
    return null
  }
  const anchorEl = findEditableAncestor(range.startContainer, root)
  const focusEl = findEditableAncestor(range.endContainer, root)
  if (!anchorEl || !focusEl) return null
  const anchorPath = parsePathKey(anchorEl.dataset.dfPath)
  const focusPath = parsePathKey(focusEl.dataset.dfPath)
  if (!anchorPath || !focusPath) return null
  return {
    anchor: {
      path: anchorPath,
      offset: offsetInEditable(anchorEl, range.startContainer, range.startOffset),
    },
    focus: {
      path: focusPath,
      offset: offsetInEditable(focusEl, range.endContainer, range.endOffset),
    },
  }
}

function setDomSelection(root: HTMLElement, selection: EditorSelection) {
  const { start, end } = normalizeSelection(selection)
  const startEl = root.querySelector(
    `[data-df-path="${pathKey(start.path)}"]`
  ) as HTMLElement | null
  const endEl = root.querySelector(
    `[data-df-path="${pathKey(end.path)}"]`
  ) as HTMLElement | null
  if (!startEl || !endEl) return

  const place = (editable: HTMLElement, offset: number): { node: Node; offset: number } | null => {
    const walker = document.createTreeWalker(editable, NodeFilter.SHOW_TEXT)
    let remaining = offset
    let textNode = walker.nextNode() as Text | null
    let last: Text | null = null
    while (textNode) {
      last = textNode
      const value = textNode.data
      if (value === "\u200b") {
        if (remaining === 0) return { node: textNode, offset: 0 }
        textNode = walker.nextNode() as Text | null
        continue
      }
      if (remaining <= value.length) {
        return { node: textNode, offset: remaining }
      }
      remaining -= value.length
      textNode = walker.nextNode() as Text | null
    }
    if (last) {
      return {
        node: last,
        offset: last.data === "\u200b" ? 0 : last.data.length,
      }
    }
    return { node: editable, offset: 0 }
  }

  const a = place(startEl, start.offset)
  const b = place(endEl, end.offset)
  if (!a || !b) return
  const range = document.createRange()
  try {
    range.setStart(a.node, a.offset)
    range.setEnd(b.node, b.offset)
  } catch {
    return
  }
  const sel = window.getSelection()
  if (!sel) return
  sel.removeAllRanges()
  sel.addRange(range)
}

function leafText(text: string): string {
  return text.length === 0 ? "\u200b" : text
}

function renderInlines(nodes: readonly InlineNode[], keyPrefix: string): React.ReactNode {
  return nodes.map((node, index) => {
    const key = `${keyPrefix}-${index}`
    if (node.type === "link") {
      return (
        <a
          key={key}
          href={node.href}
          rel="noopener noreferrer"
          target="_blank"
          data-df="editor-link"
          onClick={(event) => {
            if (!event.metaKey && !event.ctrlKey) event.preventDefault()
          }}
        >
          {renderInlines(node.children, key)}
        </a>
      )
    }
    let content: React.ReactNode = (
      <span data-df="editor-leaf">{leafText(node.text)}</span>
    )
    if (node.code) {
      content = <code data-df="editor-code">{content}</code>
    }
    if (node.bold) {
      content = <strong data-df="editor-strong">{content}</strong>
    }
    if (node.italic) {
      content = <em data-df="editor-em">{content}</em>
    }
    if (node.strikethrough) {
      content = <s data-df="editor-strike">{content}</s>
    }
    return <React.Fragment key={key}>{content}</React.Fragment>
  })
}

function isDocEmpty(doc: EditorDoc): boolean {
  if (doc.blocks.length !== 1) return false
  const block = doc.blocks[0]
  if (!block || block.type !== "paragraph") return false
  return plainTextFromInlines(block.children).trim() === ""
}

function EditorToolbarButtons({
  state,
  disabled,
  onAction,
}: {
  state: EditorState
  disabled: boolean
  onAction: (run: (prev: EditorState) => EditorState) => void
}) {
  const mark = (type: MarkType) => isMarkActive(state, type)
  const block = activeBlockType(state)

  const btn = (
    label: string,
    pressed: boolean,
    run: () => void,
    icon: React.ReactNode
  ) => (
    <Button
      key={label}
      type="button"
      size="icon-xs"
      variant="ghost"
      disabled={disabled}
      aria-label={label}
      aria-pressed={pressed}
      onMouseDown={(event) => event.preventDefault()}
      onClick={run}
    >
      {icon}
    </Button>
  )

  return (
    <>
      {btn("Bold", mark("bold"), () => onAction((s) => toggleMark(s, "bold")), <Bold />)}
      {btn("Italic", mark("italic"), () => onAction((s) => toggleMark(s, "italic")), <Italic />)}
      {btn(
        "Strikethrough",
        mark("strikethrough"),
        () => onAction((s) => toggleMark(s, "strikethrough")),
        <Strikethrough />
      )}
      {btn("Inline code", mark("code"), () => onAction((s) => toggleMark(s, "code")), <Code />)}
      {btn(
        "Link",
        false,
        () => {
          const href =
            typeof window !== "undefined"
              ? window.prompt("Link URL", "https://")
              : null
          if (href) onAction((s) => setLink(s, href))
        },
        <Link2 />
      )}
      <span data-df="editor-toolbar-sep" aria-hidden />
      {btn(
        "Heading 1",
        block?.type === "heading" && block.level === 1,
        () => onAction((s) => setBlockType(s, "heading", { level: 1 })),
        <Heading1 />
      )}
      {btn(
        "Heading 2",
        block?.type === "heading" && block.level === 2,
        () => onAction((s) => setBlockType(s, "heading", { level: 2 })),
        <Heading2 />
      )}
      {btn(
        "Heading 3",
        block?.type === "heading" && block.level === 3,
        () => onAction((s) => setBlockType(s, "heading", { level: 3 })),
        <Heading3 />
      )}
      {btn(
        "Bullet list",
        block?.type === "bullet_list",
        () => onAction((s) => setBlockType(s, "bullet_list")),
        <List />
      )}
      {btn(
        "Ordered list",
        block?.type === "ordered_list",
        () => onAction((s) => setBlockType(s, "ordered_list")),
        <ListOrdered />
      )}
      {btn(
        "Task list",
        block?.type === "task_list",
        () => onAction((s) => setBlockType(s, "task_list")),
        <ListChecks />
      )}
      {btn(
        "Quote",
        block?.type === "blockquote",
        () => onAction((s) => setBlockType(s, "blockquote")),
        <Quote />
      )}
      {btn(
        "Code block",
        block?.type === "code_block",
        () => onAction((s) => setBlockType(s, "code_block")),
        <SquareCode />
      )}
      {btn(
        "Divider",
        false,
        () => onAction((s) => setBlockType(s, "divider")),
        <Minus />
      )}
    </>
  )
}

function renderBlock(
  block: BlockNode,
  blockIndex: number,
  readOnly: boolean,
  onToggleTask: (path: EditorPath) => void
): React.ReactNode {
  if (block.type === "paragraph") {
    return (
      <p key={blockIndex} data-df="editor-paragraph" data-df-path={pathKey([blockIndex])}>
        {renderInlines(block.children, `p-${blockIndex}`)}
      </p>
    )
  }
  if (block.type === "heading") {
    const Tag = (`h${block.level}` as "h1" | "h2" | "h3")
    return (
      <Tag
        key={blockIndex}
        data-df="editor-heading"
        data-level={block.level}
        data-df-path={pathKey([blockIndex])}
      >
        {renderInlines(block.children, `h-${blockIndex}`)}
      </Tag>
    )
  }
  if (block.type === "blockquote") {
    return (
      <blockquote
        key={blockIndex}
        data-df="editor-quote"
        data-df-path={pathKey([blockIndex])}
      >
        {renderInlines(block.children, `q-${blockIndex}`)}
      </blockquote>
    )
  }
  if (block.type === "code_block") {
    return (
      <pre
        key={blockIndex}
        data-df="editor-code-block"
        data-df-path={pathKey([blockIndex])}
        spellCheck={false}
      >
        <code>{leafText(block.value)}</code>
      </pre>
    )
  }
  if (block.type === "divider") {
    return (
      <hr
        key={blockIndex}
        data-df="editor-divider"
        data-df-path={pathKey([blockIndex])}
        contentEditable={false}
      />
    )
  }
  if (block.type === "raw") {
    return (
      <pre
        key={blockIndex}
        data-df="editor-raw"
        data-df-path={pathKey([blockIndex])}
        contentEditable={false}
      >
        {block.markdown}
      </pre>
    )
  }
  if (block.type === "bullet_list") {
    return (
      <ul key={blockIndex} data-df="editor-bullet-list">
        {block.items.map((item, itemIndex) => (
          <li
            key={itemIndex}
            data-df="editor-list-item"
            data-df-path={pathKey([blockIndex, itemIndex])}
          >
            {renderInlines(item.children, `ul-${blockIndex}-${itemIndex}`)}
          </li>
        ))}
      </ul>
    )
  }
  if (block.type === "ordered_list") {
    return (
      <ol key={blockIndex} data-df="editor-ordered-list">
        {block.items.map((item, itemIndex) => (
          <li
            key={itemIndex}
            data-df="editor-list-item"
            data-df-path={pathKey([blockIndex, itemIndex])}
          >
            {renderInlines(item.children, `ol-${blockIndex}-${itemIndex}`)}
          </li>
        ))}
      </ol>
    )
  }
  return (
    <ul key={blockIndex} data-df="editor-task-list">
      {block.items.map((item, itemIndex) => {
        const path: EditorPath = [blockIndex, itemIndex]
        return (
          <li
            key={itemIndex}
            data-df="editor-task-item"
            data-df-path={pathKey(path)}
            data-checked={item.checked ? "true" : "false"}
          >
            <span
              data-df="checkbox"
              data-size="sm"
              data-state={item.checked ? "checked" : "unchecked"}
              data-disabled={readOnly ? "" : undefined}
              contentEditable={false}
              className="df-editor-task-check"
            >
              <button
                type="button"
                data-df="checkbox-input"
                role="checkbox"
                aria-checked={item.checked}
                aria-label={item.checked ? "Mark task incomplete" : "Mark task complete"}
                disabled={readOnly}
                tabIndex={readOnly ? -1 : 0}
                onMouseDown={(event) => event.preventDefault()}
                onClick={() => onToggleTask(path)}
                onKeyDown={(event) => {
                  if (readOnly) return
                  if (event.key === " " || event.key === "Enter") {
                    event.preventDefault()
                    event.stopPropagation()
                    onToggleTask(path)
                  }
                }}
              />
              <span data-df="checkbox-box" aria-hidden>
                {item.checked ? <Check data-df="checkbox-icon" /> : null}
              </span>
            </span>
            <span data-df="editor-task-text">
              {renderInlines(item.children, `task-${blockIndex}-${itemIndex}`)}
            </span>
          </li>
        )
      })}
    </ul>
  )
}

function Editor({
  value,
  onChange,
  placeholder = "Write…",
  readOnly = false,
  minHeight,
  toolbar = "both",
  autoFocus = false,
  className,
  "aria-label": ariaLabel = "Editor",
}: EditorProps) {
  const surfaceRef = React.useRef<HTMLDivElement>(null)
  const settleTimer = React.useRef<ReturnType<typeof setTimeout> | null>(null)
  const pendingDocRef = React.useRef<EditorDoc | null>(null)
  const onChangeRef = React.useRef(onChange)
  const skipSelectionSync = React.useRef(false)
  const floatingOffsetRef = React.useRef(0)
  const rootRef = React.useRef<HTMLDivElement>(null)
  const stateRef = React.useRef<EditorState>({
    doc: parseMarkdown(value),
    selection: collapsedSelection([0], 0),
  })

  const [state, setState] = React.useState<EditorState>(stateRef.current)
  const [floating, setFloating] = React.useState<FloatingPos | null>(null)
  const [showFloating, setShowFloating] = React.useState(false)

  onChangeRef.current = onChange

  const emitChange = React.useCallback((doc: EditorDoc) => {
    if (!onChangeRef.current) return
    pendingDocRef.current = doc
    if (settleTimer.current) clearTimeout(settleTimer.current)
    settleTimer.current = setTimeout(() => {
      settleTimer.current = null
      const pending = pendingDocRef.current
      pendingDocRef.current = null
      if (pending) onChangeRef.current?.(serializeMarkdown(pending))
    }, SETTLE_MS)
  }, [])

  const flushChange = React.useCallback((doc: EditorDoc) => {
    if (settleTimer.current) {
      clearTimeout(settleTimer.current)
      settleTimer.current = null
    }
    pendingDocRef.current = null
    onChangeRef.current?.(serializeMarkdown(doc))
  }, [])

  React.useEffect(() => {
    return () => {
      if (settleTimer.current) {
        clearTimeout(settleTimer.current)
        settleTimer.current = null
      }
      const pending = pendingDocRef.current
      pendingDocRef.current = null
      if (pending) onChangeRef.current?.(serializeMarkdown(pending))
    }
  }, [])

  React.useEffect(() => {
    const el = rootRef.current
    if (!el) return
    const raw = getComputedStyle(el).getPropertyValue("--df-editor-floating-offset").trim()
    const px = Number.parseFloat(raw)
    if (Number.isFinite(px) && px >= 0) floatingOffsetRef.current = px
  }, [])

  React.useEffect(() => {
    const current = serializeMarkdown(stateRef.current.doc)
    if (current === value || (value.trim() === "" && isDocEmpty(stateRef.current.doc))) {
      return
    }
    const next: EditorState = {
      doc: parseMarkdown(value),
      selection: stateRef.current.selection,
    }
    stateRef.current = next
    setState(next)
  }, [value])

  const commit = React.useCallback(
    (next: EditorState, opts?: { flush?: boolean }) => {
      stateRef.current = next
      setState(next)
      skipSelectionSync.current = true
      if (opts?.flush) flushChange(next.doc)
      else emitChange(next.doc)
      requestAnimationFrame(() => {
        const root = surfaceRef.current
        if (!root || readOnly) return
        setDomSelection(root, next.selection)
        skipSelectionSync.current = false
      })
    },
    [emitChange, flushChange, readOnly]
  )

  React.useEffect(() => {
    if (!autoFocus || readOnly) return
    surfaceRef.current?.focus()
  }, [autoFocus, readOnly])

  const updateFloatingFromSelection = React.useCallback(() => {
    if (toolbar !== "floating" && toolbar !== "both") {
      setShowFloating(false)
      return
    }
    if (readOnly) {
      setShowFloating(false)
      return
    }
    const sel = window.getSelection()
    const root = surfaceRef.current
    if (!sel || !root || sel.rangeCount === 0 || sel.isCollapsed) {
      setShowFloating(false)
      return
    }
    if (!root.contains(sel.anchorNode)) {
      setShowFloating(false)
      return
    }
    const range = sel.getRangeAt(0)
    const rect = range.getBoundingClientRect()
    if (rect.width === 0 && rect.height === 0) {
      setShowFloating(false)
      return
    }
    setFloating({
      top: rect.top - floatingOffsetRef.current,
      left: rect.left + rect.width / 2,
    })
    setShowFloating(true)
  }, [readOnly, toolbar])

  React.useEffect(() => {
    const onSelectionChange = () => {
      if (skipSelectionSync.current) return
      const root = surfaceRef.current
      if (!root) return
      const model = readDomSelection(root)
      if (model) {
        stateRef.current = { ...stateRef.current, selection: model }
        setState((prev) => ({ ...prev, selection: model }))
      }
      updateFloatingFromSelection()
    }
    document.addEventListener("selectionchange", onSelectionChange)
    return () => document.removeEventListener("selectionchange", onSelectionChange)
  }, [updateFloatingFromSelection])

  const run = React.useCallback(
    (recipe: (prev: EditorState) => EditorState, opts?: { flush?: boolean }) => {
      if (readOnly) return
      commit(recipe(stateRef.current), opts)
    },
    [commit, readOnly]
  )

  const onBeforeInput = (event: React.FormEvent<HTMLDivElement>) => {
    if (readOnly) {
      event.preventDefault()
      return
    }
    const native = event.nativeEvent as InputEvent
    const type = native.inputType
    const data = native.data ?? ""

    if (type === "insertText" || type === "insertCompositionText") {
      event.preventDefault()
      if (!data) return
      run((prev) => {
        let next = insertText(prev, data)
        if (data === " " || data === "\n") {
          next = applyInputRule(next, data)
        }
        return next
      })
      return
    }

    if (type === "insertParagraph" || type === "insertLineBreak") {
      event.preventDefault()
      const block = stateRef.current.doc.blocks[
        normalizeSelection(stateRef.current.selection).start.path[0] ?? 0
      ]
      if (block?.type === "code_block" || type === "insertLineBreak") {
        run((prev) => insertText(prev, "\n"))
        return
      }
      run((prev) => {
        const ruled = applyInputRule(prev, "\n")
        if (ruled !== prev) return ruled
        return splitBlock(prev)
      })
      return
    }

    if (type === "deleteContentBackward" || type === "deleteContentForward") {
      event.preventDefault()
      if (type === "deleteContentBackward") {
        run((prev) => deleteBackward(prev))
      } else if (!selectionIsCollapsed(stateRef.current.selection)) {
        run((prev) => deleteSelection(prev))
      }
      return
    }

    if (type.startsWith("format")) {
      event.preventDefault()
    }
  }

  const onKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    if (readOnly) return
    const mod = event.metaKey || event.ctrlKey
    const block = stateRef.current.doc.blocks[
      normalizeSelection(stateRef.current.selection).start.path[0] ?? 0
    ]

    if (event.key === "Tab" && block?.type === "code_block") {
      event.preventDefault()
      run((prev) => insertText(prev, "  "))
      return
    }

    if (mod && event.key.toLowerCase() === "b") {
      event.preventDefault()
      run((prev) => toggleMark(prev, "bold"))
      return
    }
    if (mod && event.key.toLowerCase() === "i") {
      event.preventDefault()
      run((prev) => toggleMark(prev, "italic"))
      return
    }
    if (mod && event.key.toLowerCase() === "k") {
      event.preventDefault()
      const href =
        typeof window !== "undefined" ? window.prompt("Link URL", "https://") : null
      if (href) run((prev) => setLink(prev, href))
      return
    }
  }

  const onPaste = (event: React.ClipboardEvent<HTMLDivElement>) => {
    if (readOnly) return
    event.preventDefault()
    const text = event.clipboardData.getData("text/plain")
    if (!text) return
    run((prev) => pasteMarkdown(prev, text))
  }

  const onBlur = () => {
    flushChange(stateRef.current.doc)
    setShowFloating(false)
  }

  const showStatic = toolbar === "static" || toolbar === "both"
  const empty = isDocEmpty(state.doc)
  const style = minHeight
    ? ({ ["--df-editor-min-height" as string]: minHeight } as React.CSSProperties)
    : undefined

  return (
    <div
      ref={rootRef}
      data-df="editor"
      className={cn("df-editor", className)}
      data-readonly={readOnly ? "true" : undefined}
      style={style}
    >
      {showStatic ? (
        <div
          className="df-editor-toolbar"
          data-df="editor-toolbar"
          role="toolbar"
          aria-label="Formatting"
        >
          <EditorToolbarButtons
            state={state}
            disabled={readOnly}
            onAction={(recipe) => run(recipe)}
          />
        </div>
      ) : null}

      <div className="df-editor-surface-wrap" data-df="editor-surface-wrap">
        {empty ? (
          <p className="df-editor-placeholder" aria-hidden="true">
            {placeholder}
          </p>
        ) : null}
        <div
          ref={surfaceRef}
          className="df-editor-surface"
          data-df="editor-surface"
          role="textbox"
          aria-multiline="true"
          aria-label={ariaLabel}
          aria-readonly={readOnly || undefined}
          contentEditable={!readOnly}
          suppressContentEditableWarning
          spellCheck
          onBeforeInput={onBeforeInput}
          onKeyDown={onKeyDown}
          onPaste={onPaste}
          onBlur={onBlur}
        >
          {state.doc.blocks.map((block, index) =>
            renderBlock(block, index, readOnly, (path) =>
              run((prev) => toggleTaskChecked(prev, path))
            )
          )}
        </div>
      </div>

      {showFloating && floating ? (
        <div
          className="df-editor-floating-toolbar"
          data-df="editor-floating-toolbar"
          role="toolbar"
          aria-label="Selection formatting"
          style={{
            top: floating.top,
            left: floating.left,
            transform: "translate(-50%, -100%)",
          }}
        >
          <EditorToolbarButtons
            state={state}
            disabled={readOnly}
            onAction={(recipe) => run(recipe)}
          />
        </div>
      ) : null}
    </div>
  )
}

const DfEditor = Editor

export { Editor, DfEditor }
export type { EditorProps as DfEditorProps }

/** Markdown-backed AST for df-editor. Public value is always a markdown string. */

export type MarkType = "bold" | "italic" | "code" | "strikethrough"

export type TextInline = {
  type: "text"
  text: string
  bold?: boolean
  italic?: boolean
  code?: boolean
  strikethrough?: boolean
}

export type LinkInline = {
  type: "link"
  href: string
  children: TextInline[]
}

export type InlineNode = TextInline | LinkInline

export type ListItemNode = {
  type: "list_item"
  children: InlineNode[]
}

export type TaskItemNode = {
  type: "task_item"
  checked: boolean
  children: InlineNode[]
}

export type ParagraphBlock = {
  type: "paragraph"
  children: InlineNode[]
}

export type HeadingBlock = {
  type: "heading"
  level: 1 | 2 | 3
  children: InlineNode[]
}

export type BlockquoteBlock = {
  type: "blockquote"
  children: InlineNode[]
}

export type CodeBlock = {
  type: "code_block"
  language: string
  value: string
}

export type DividerBlock = {
  type: "divider"
}

export type BulletListBlock = {
  type: "bullet_list"
  items: ListItemNode[]
}

export type OrderedListBlock = {
  type: "ordered_list"
  items: ListItemNode[]
}

export type TaskListBlock = {
  type: "task_list"
  items: TaskItemNode[]
}

/** Opaque markdown preserved for unsupported constructs. Never reformatted. */
export type RawBlock = {
  type: "raw"
  markdown: string
}

export type BlockNode =
  | ParagraphBlock
  | HeadingBlock
  | BlockquoteBlock
  | CodeBlock
  | DividerBlock
  | BulletListBlock
  | OrderedListBlock
  | TaskListBlock
  | RawBlock

export type EditorDoc = {
  type: "doc"
  blocks: BlockNode[]
}

/** Path into the document: [blockIndex] or [blockIndex, itemIndex] for list items. */
export type EditorPath = readonly number[]

export type EditorPoint = {
  path: EditorPath
  offset: number
}

export type EditorSelection = {
  anchor: EditorPoint
  focus: EditorPoint
}

export type EditorState = {
  doc: EditorDoc
  selection: EditorSelection
}

export function emptyDoc(): EditorDoc {
  return {
    type: "doc",
    blocks: [createParagraph()],
  }
}

export function createParagraph(children: InlineNode[] = [createText("")]): ParagraphBlock {
  return { type: "paragraph", children: children.length ? children : [createText("")] }
}

export function createHeading(
  level: 1 | 2 | 3,
  children: InlineNode[] = [createText("")]
): HeadingBlock {
  return { type: "heading", level, children: children.length ? children : [createText("")] }
}

export function createBlockquote(
  children: InlineNode[] = [createText("")]
): BlockquoteBlock {
  return { type: "blockquote", children: children.length ? children : [createText("")] }
}

export function createCodeBlock(value = "", language = ""): CodeBlock {
  return { type: "code_block", language, value }
}

export function createDivider(): DividerBlock {
  return { type: "divider" }
}

export function createBulletList(items?: ListItemNode[]): BulletListBlock {
  return {
    type: "bullet_list",
    items: items?.length ? items : [{ type: "list_item", children: [createText("")] }],
  }
}

export function createOrderedList(items?: ListItemNode[]): OrderedListBlock {
  return {
    type: "ordered_list",
    items: items?.length ? items : [{ type: "list_item", children: [createText("")] }],
  }
}

export function createTaskList(items?: TaskItemNode[]): TaskListBlock {
  return {
    type: "task_list",
    items: items?.length
      ? items
      : [{ type: "task_item", checked: false, children: [createText("")] }],
  }
}

export function createRawBlock(markdown: string): RawBlock {
  return { type: "raw", markdown }
}

export function createText(
  text: string,
  marks: Partial<Record<MarkType, boolean>> = {}
): TextInline {
  const node: TextInline = { type: "text", text }
  if (marks.bold) node.bold = true
  if (marks.italic) node.italic = true
  if (marks.code) node.code = true
  if (marks.strikethrough) node.strikethrough = true
  return node
}

export function createLink(href: string, text: string): LinkInline {
  return { type: "link", href, children: [createText(text)] }
}

export function isTextInline(node: InlineNode): node is TextInline {
  return node.type === "text"
}

export function isLinkInline(node: InlineNode): node is LinkInline {
  return node.type === "link"
}

export function isListBlock(
  block: BlockNode
): block is BulletListBlock | OrderedListBlock | TaskListBlock {
  return (
    block.type === "bullet_list" ||
    block.type === "ordered_list" ||
    block.type === "task_list"
  )
}

export function isInlineBlock(
  block: BlockNode
): block is ParagraphBlock | HeadingBlock | BlockquoteBlock {
  return (
    block.type === "paragraph" ||
    block.type === "heading" ||
    block.type === "blockquote"
  )
}

export function collapsedSelection(path: EditorPath, offset: number): EditorSelection {
  const point = { path: [...path], offset }
  return { anchor: point, focus: { ...point, path: [...path] } }
}

export function selectionIsCollapsed(selection: EditorSelection): boolean {
  return (
    pathEquals(selection.anchor.path, selection.focus.path) &&
    selection.anchor.offset === selection.focus.offset
  )
}

export function pathEquals(a: EditorPath, b: EditorPath): boolean {
  if (a.length !== b.length) return false
  for (let i = 0; i < a.length; i += 1) {
    if (a[i] !== b[i]) return false
  }
  return true
}

export function comparePoints(a: EditorPoint, b: EditorPoint): number {
  const len = Math.max(a.path.length, b.path.length)
  for (let i = 0; i < len; i += 1) {
    const av = a.path[i] ?? -1
    const bv = b.path[i] ?? -1
    if (av !== bv) return av < bv ? -1 : 1
  }
  if (a.offset !== b.offset) return a.offset < b.offset ? -1 : 1
  return 0
}

export function normalizeSelection(selection: EditorSelection): {
  start: EditorPoint
  end: EditorPoint
  isCollapsed: boolean
} {
  const cmp = comparePoints(selection.anchor, selection.focus)
  if (cmp <= 0) {
    return {
      start: selection.anchor,
      end: selection.focus,
      isCollapsed: cmp === 0,
    }
  }
  return {
    start: selection.focus,
    end: selection.anchor,
    isCollapsed: false,
  }
}

export function plainTextFromInlines(nodes: readonly InlineNode[]): string {
  return nodes
    .map((node) => {
      if (node.type === "link") return plainTextFromInlines(node.children)
      return node.text
    })
    .join("")
}

export function hasMark(node: TextInline, mark: MarkType): boolean {
  if (mark === "bold") return node.bold === true
  if (mark === "italic") return node.italic === true
  if (mark === "code") return node.code === true
  return node.strikethrough === true
}

export function withMark(node: TextInline, mark: MarkType, on: boolean): TextInline {
  const next: TextInline = { type: "text", text: node.text }
  const bold = mark === "bold" ? on : node.bold === true
  const italic = mark === "italic" ? on : node.italic === true
  const code = mark === "code" ? on : node.code === true
  const strikethrough = mark === "strikethrough" ? on : node.strikethrough === true
  if (bold) next.bold = true
  if (italic) next.italic = true
  if (code) next.code = true
  if (strikethrough) next.strikethrough = true
  return next
}

export function marksEqual(a: TextInline, b: TextInline): boolean {
  return (
    a.bold === b.bold &&
    a.italic === b.italic &&
    a.code === b.code &&
    a.strikethrough === b.strikethrough
  )
}

import {
  createCodeBlock,
  createDivider,
  createHeading,
  createParagraph,
  createRawBlock,
  createText,
  emptyDoc,
  marksEqual,
  type BlockNode,
  type BulletListBlock,
  type EditorDoc,
  type InlineNode,
  type ListItemNode,
  type OrderedListBlock,
  type TaskItemNode,
  type TaskListBlock,
  type TextInline,
} from "./ast"
import { sanitizeHref } from "./url"

const HEADING_RE = /^(#{1,3})[ \t]+(.*)$/
const BULLET_RE = /^([ \t]*)([-*+])[ \t]+(.*)$/
const ORDERED_RE = /^([ \t]*)(\d+)\.[ \t]+(.*)$/
const TASK_RE = /^([ \t]*)([-*+])[ \t]+\[([ xX])\][ \t]+(.*)$/
const BLOCKQUOTE_RE = /^>[ \t]?(.*)$/
/** Opening fence: 3 or more backticks, optional info string. */
const FENCE_OPEN_RE = /^(`{3,})([\w-]*)[ \t]*$/
/** Closing fence candidate: 3 or more backticks, no info string. */
const FENCE_CLOSE_RE = /^(`{3,})[ \t]*$/
const DIVIDER_RE = /^(?:-{3,}|\*{3,}|_{3,})[ \t]*$/
const TABLE_LINE_RE = /^\s*\|.*\|\s*$/
const TABLE_ALIGN_RE = /^\s*\|?\s*:?-+:?\s*(\|\s*:?-+:?\s*)+\|?\s*$/
const HTML_BLOCK_RE = /^\s*<\/?[a-zA-Z][\w:-]*[\s>]/
const FOOTNOTE_DEF_RE = /^\[\^[^\]]+\]:/
const LINK_DEF_RE = /^\[[^\]]+\]:\s+\S+/

function unescapeText(value: string): string {
  return value.replace(/\\([\\`*_{}[\]()#+\-.!|>~])/g, "$1")
}

function mergeInlines(nodes: InlineNode[]): InlineNode[] {
  const out: InlineNode[] = []
  for (const node of nodes) {
    if (node.type === "link") {
      out.push({
        type: "link",
        href: node.href,
        children: mergeInlines(node.children) as TextInline[],
      })
      continue
    }
    const last = out[out.length - 1]
    if (last && last.type === "text" && marksEqual(last, node)) {
      last.text += node.text
    } else {
      out.push({ ...node })
    }
  }
  return out.length ? out : [createText("")]
}

function applyMarks(nodes: InlineNode[], marks: Partial<TextInline>): InlineNode[] {
  return nodes.map((node) => {
    if (node.type === "link") {
      return {
        type: "link" as const,
        href: node.href,
        children: applyMarks(node.children, marks) as TextInline[],
      }
    }
    return createText(node.text, {
      bold: marks.bold || node.bold,
      italic: marks.italic || node.italic,
      code: marks.code || node.code,
      strikethrough: marks.strikethrough || node.strikethrough,
    })
  })
}

/**
 * Parse an inline code span starting at `start`.
 * Opening run of N backticks closes at the next run of exactly N backticks.
 * Content is preserved verbatim; a single leading and trailing space is trimmed
 * when content both starts and ends with a space and is not all spaces.
 */
function parseInlineCodeSpan(
  input: string,
  start: number
): { text: string; end: number } | null {
  if (input[start] !== "`") return null
  let openLen = 0
  while (start + openLen < input.length && input[start + openLen] === "`") {
    openLen += 1
  }
  if (openLen === 0) return null

  let i = start + openLen
  while (i < input.length) {
    if (input[i] !== "`") {
      i += 1
      continue
    }
    let closeLen = 0
    while (i + closeLen < input.length && input[i + closeLen] === "`") {
      closeLen += 1
    }
    if (closeLen === openLen) {
      let content = input.slice(start + openLen, i)
      if (
        content.length >= 2 &&
        content.startsWith(" ") &&
        content.endsWith(" ") &&
        content.trim() !== ""
      ) {
        content = content.slice(1, -1)
      }
      return { text: content, end: i + closeLen }
    }
    i += closeLen
  }
  return null
}

function parseFenceOpen(
  line: string
): { length: number; language: string } | null {
  const match = FENCE_OPEN_RE.exec(line)
  if (!match) return null
  return { length: match[1]!.length, language: match[2] ?? "" }
}

function isFenceClose(line: string, openLength: number): boolean {
  const match = FENCE_CLOSE_RE.exec(line)
  if (!match) return false
  return match[1]!.length >= openLength
}

function parseInlines(input: string): InlineNode[] {
  const nodes: InlineNode[] = []
  let i = 0

  const pushPlain = (text: string) => {
    if (!text) return
    nodes.push(createText(text))
  }

  while (i < input.length) {
    if (input[i] === "\\" && i + 1 < input.length) {
      pushPlain(input[i + 1]!)
      i += 2
      continue
    }

    if (input[i] === "`") {
      const span = parseInlineCodeSpan(input, i)
      if (span) {
        nodes.push(createText(span.text, { code: true }))
        i = span.end
        continue
      }
    }

    if (input.startsWith("~~", i)) {
      const end = input.indexOf("~~", i + 2)
      if (end !== -1) {
        nodes.push(
          ...applyMarks(parseInlines(input.slice(i + 2, end)), {
            strikethrough: true,
          })
        )
        i = end + 2
        continue
      }
    }

    if (input.startsWith("***", i)) {
      const end = input.indexOf("***", i + 3)
      if (end !== -1) {
        nodes.push(
          ...applyMarks(parseInlines(input.slice(i + 3, end)), {
            bold: true,
            italic: true,
          })
        )
        i = end + 3
        continue
      }
    }

    if (input.startsWith("**", i)) {
      const end = input.indexOf("**", i + 2)
      if (end !== -1) {
        nodes.push(
          ...applyMarks(parseInlines(input.slice(i + 2, end)), { bold: true })
        )
        i = end + 2
        continue
      }
    }

    if (input[i] === "*" && input[i + 1] !== "*") {
      let end = -1
      for (let j = i + 1; j < input.length; j += 1) {
        if (input[j] === "\\") {
          j += 1
          continue
        }
        if (input[j] === "*" && input[j + 1] !== "*") {
          end = j
          break
        }
      }
      if (end !== -1) {
        nodes.push(
          ...applyMarks(parseInlines(input.slice(i + 1, end)), { italic: true })
        )
        i = end + 1
        continue
      }
    }

    if (input[i] === "_" && input[i + 1] !== "_") {
      let end = -1
      for (let j = i + 1; j < input.length; j += 1) {
        if (input[j] === "\\") {
          j += 1
          continue
        }
        if (input[j] === "_" && input[j + 1] !== "_") {
          end = j
          break
        }
      }
      if (end !== -1) {
        nodes.push(
          ...applyMarks(parseInlines(input.slice(i + 1, end)), { italic: true })
        )
        i = end + 1
        continue
      }
    }

    if (input[i] === "[") {
      const labelEnd = input.indexOf("]", i + 1)
      if (labelEnd !== -1 && input[labelEnd + 1] === "(") {
        const hrefEnd = findClosingParen(input, labelEnd + 2)
        if (hrefEnd !== -1) {
          const label = unescapeText(input.slice(i + 1, labelEnd))
          const hrefRaw = input.slice(labelEnd + 2, hrefEnd).trim()
          const hrefOnly =
            hrefRaw.replace(/^<([^>]+)>$/, "$1").split(/\s+/)[0] ?? ""
          const href = sanitizeHref(hrefOnly)
          if (href) {
            nodes.push({
              type: "link",
              href,
              children: [createText(label)],
            })
          } else {
            pushPlain(input.slice(i, hrefEnd + 1))
          }
          i = hrefEnd + 1
          continue
        }
      }
    }

    pushPlain(input[i]!)
    i += 1
  }

  return mergeInlines(nodes)
}

function findClosingParen(input: string, from: number): number {
  let depth = 1
  for (let i = from; i < input.length; i += 1) {
    if (input[i] === "\\") {
      i += 1
      continue
    }
    if (input[i] === "(") depth += 1
    else if (input[i] === ")") {
      depth -= 1
      if (depth === 0) return i
    }
  }
  return -1
}

function isBlank(line: string): boolean {
  return line.trim() === ""
}

function looksUnsupported(line: string): boolean {
  return (
    TABLE_LINE_RE.test(line) ||
    TABLE_ALIGN_RE.test(line) ||
    HTML_BLOCK_RE.test(line) ||
    FOOTNOTE_DEF_RE.test(line) ||
    LINK_DEF_RE.test(line)
  )
}

function collectRaw(
  lines: string[],
  start: number
): { block: BlockNode; next: number } {
  const chunk: string[] = [lines[start]!]
  let i = start + 1
  if (TABLE_LINE_RE.test(lines[start]!) || TABLE_ALIGN_RE.test(lines[start]!)) {
    while (
      i < lines.length &&
      (TABLE_LINE_RE.test(lines[i]!) || TABLE_ALIGN_RE.test(lines[i]!))
    ) {
      chunk.push(lines[i]!)
      i += 1
    }
  } else if (HTML_BLOCK_RE.test(lines[start]!)) {
    while (i < lines.length && !isBlank(lines[i]!)) {
      chunk.push(lines[i]!)
      i += 1
    }
  } else {
    while (i < lines.length && !isBlank(lines[i]!)) {
      chunk.push(lines[i]!)
      i += 1
    }
  }
  return { block: createRawBlock(chunk.join("\n")), next: i }
}

function lineStartsFence(line: string): boolean {
  return parseFenceOpen(line) !== null
}

/**
 * Parse a markdown string into the editor AST.
 * Supported constructs become typed blocks; tables, HTML, and footnotes become raw blocks.
 */
export function parseMarkdown(source: string): EditorDoc {
  const normalized = source.replace(/\r\n/g, "\n").replace(/\r/g, "\n")
  if (normalized.trim() === "") return emptyDoc()

  const lines = normalized.split("\n")
  // Drop a single trailing empty line from split of trailing newline.
  if (lines.length && lines[lines.length - 1] === "") lines.pop()

  const blocks: BlockNode[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]!

    if (isBlank(line)) {
      i += 1
      continue
    }

    const fenceOpen = parseFenceOpen(line)
    if (fenceOpen) {
      const body: string[] = []
      i += 1
      while (i < lines.length) {
        if (isFenceClose(lines[i]!, fenceOpen.length)) {
          i += 1
          break
        }
        body.push(lines[i]!)
        i += 1
      }
      // Unterminated fence consumes remaining lines into the body; no phantom blocks.
      blocks.push(createCodeBlock(body.join("\n"), fenceOpen.language))
      continue
    }

    if (looksUnsupported(line)) {
      const raw = collectRaw(lines, i)
      blocks.push(raw.block)
      i = raw.next
      continue
    }

    if (DIVIDER_RE.test(line)) {
      blocks.push(createDivider())
      i += 1
      continue
    }

    const heading = HEADING_RE.exec(line)
    if (heading) {
      const level = heading[1]!.length as 1 | 2 | 3
      blocks.push(createHeading(level, parseInlines(heading[2] ?? "")))
      i += 1
      continue
    }

    const quote = BLOCKQUOTE_RE.exec(line)
    if (quote) {
      const parts: string[] = [quote[1] ?? ""]
      i += 1
      while (i < lines.length) {
        const next = BLOCKQUOTE_RE.exec(lines[i]!)
        if (!next) break
        parts.push(next[1] ?? "")
        i += 1
      }
      blocks.push({
        type: "blockquote",
        children: parseInlines(parts.join(" ")),
      })
      continue
    }

    const task = TASK_RE.exec(line)
    if (task) {
      const items: TaskItemNode[] = [
        {
          type: "task_item",
          checked: task[3]!.toLowerCase() === "x",
          children: parseInlines(task[4] ?? ""),
        },
      ]
      i += 1
      while (i < lines.length) {
        const next = TASK_RE.exec(lines[i]!)
        if (!next) break
        items.push({
          type: "task_item",
          checked: next[3]!.toLowerCase() === "x",
          children: parseInlines(next[4] ?? ""),
        })
        i += 1
      }
      const list: TaskListBlock = { type: "task_list", items }
      blocks.push(list)
      continue
    }

    const bullet = BULLET_RE.exec(line)
    if (bullet) {
      const items: ListItemNode[] = [
        { type: "list_item", children: parseInlines(bullet[3] ?? "") },
      ]
      i += 1
      while (i < lines.length) {
        if (TASK_RE.test(lines[i]!)) break
        const next = BULLET_RE.exec(lines[i]!)
        if (!next) break
        items.push({
          type: "list_item",
          children: parseInlines(next[3] ?? ""),
        })
        i += 1
      }
      const list: BulletListBlock = { type: "bullet_list", items }
      blocks.push(list)
      continue
    }

    const ordered = ORDERED_RE.exec(line)
    if (ordered) {
      const items: ListItemNode[] = [
        { type: "list_item", children: parseInlines(ordered[3] ?? "") },
      ]
      i += 1
      while (i < lines.length) {
        const next = ORDERED_RE.exec(lines[i]!)
        if (!next) break
        items.push({
          type: "list_item",
          children: parseInlines(next[3] ?? ""),
        })
        i += 1
      }
      const list: OrderedListBlock = { type: "ordered_list", items }
      blocks.push(list)
      continue
    }

    const paraLines: string[] = [line]
    i += 1
    while (i < lines.length) {
      const next = lines[i]!
      if (isBlank(next)) break
      if (
        lineStartsFence(next) ||
        DIVIDER_RE.test(next) ||
        HEADING_RE.test(next) ||
        BLOCKQUOTE_RE.test(next) ||
        TASK_RE.test(next) ||
        BULLET_RE.test(next) ||
        ORDERED_RE.test(next) ||
        looksUnsupported(next)
      ) {
        break
      }
      paraLines.push(next)
      i += 1
    }
    blocks.push(createParagraph(parseInlines(paraLines.join(" "))))
  }

  if (blocks.length === 0) return emptyDoc()
  return { type: "doc", blocks }
}

import {
  plainTextFromInlines,
  type BlockNode,
  type EditorDoc,
  type InlineNode,
  type MarkType,
  type TextInline,
} from "./ast"

function escapeText(value: string): string {
  return value.replace(/([\\`*_{}[\]()#+\-.!|>~])/g, "\\$1")
}

/** Longest consecutive backtick run in `value`. */
export function maxBacktickRun(value: string): number {
  let max = 0
  let run = 0
  for (let i = 0; i < value.length; i += 1) {
    if (value[i] === "`") {
      run += 1
      if (run > max) max = run
    } else {
      run = 0
    }
  }
  return max
}

/**
 * Fence length for a code block: at least 3, and longer than any backtick run in the body.
 */
export function codeBlockFenceLength(body: string): number {
  return Math.max(3, maxBacktickRun(body) + 1)
}

/**
 * Fence length for an inline code span: longer than any backtick run in the content (min 1).
 */
export function inlineCodeFenceLength(content: string): number {
  return Math.max(1, maxBacktickRun(content) + 1)
}

function serializeInlineCode(content: string): string {
  const fence = "`".repeat(inlineCodeFenceLength(content))
  // Pad with one space when content would confuse the fence or needs space preservation.
  const needsPad =
    content.length === 0 ||
    content.startsWith("`") ||
    content.endsWith("`") ||
    content.startsWith(" ") ||
    content.endsWith(" ")
  const body = needsPad ? ` ${content} ` : content
  return `${fence}${body}${fence}`
}

type FlatSeg = {
  text: string
  bold: boolean
  italic: boolean
  code: boolean
  strikethrough: boolean
  linkHref?: string
}

function flatten(nodes: readonly InlineNode[]): FlatSeg[] {
  const segs: FlatSeg[] = []
  for (const node of nodes) {
    if (node.type === "link") {
      for (const child of node.children) {
        segs.push({
          text: child.text,
          bold: child.bold === true,
          italic: child.italic === true,
          code: child.code === true,
          strikethrough: child.strikethrough === true,
          linkHref: node.href,
        })
      }
      continue
    }
    segs.push({
      text: node.text,
      bold: node.bold === true,
      italic: node.italic === true,
      code: node.code === true,
      strikethrough: node.strikethrough === true,
    })
  }
  return segs
}

/** Outer-to-inner mark order for delimiter emission. Italic uses `_` to avoid `*`/`**` collisions. */
const MARK_ORDER: MarkType[] = ["strikethrough", "bold", "italic"]

function openMark(mark: MarkType): string {
  if (mark === "strikethrough") return "~~"
  if (mark === "bold") return "**"
  return "_"
}

function closeMark(mark: MarkType): string {
  return openMark(mark)
}

/**
 * Serialize inline nodes with a mark delimiter state machine so adjacent runs
 * sharing bold/italic do not emit colliding `**`/`*` sequences.
 */
function serializeInlines(nodes: readonly InlineNode[]): string {
  const segs = flatten(nodes)
  if (segs.length === 0) return ""

  let out = ""
  let i = 0
  const active: Partial<Record<MarkType, boolean>> = {}

  const closeDownTo = (keep: Partial<Record<MarkType, boolean>>) => {
    for (let m = MARK_ORDER.length - 1; m >= 0; m -= 1) {
      const mark = MARK_ORDER[m]!
      if (active[mark] && !keep[mark]) {
        out += closeMark(mark)
        active[mark] = false
      }
    }
  }

  const openUpTo = (target: Partial<Record<MarkType, boolean>>) => {
    for (const mark of MARK_ORDER) {
      if (target[mark] && !active[mark]) {
        out += openMark(mark)
        active[mark] = true
      }
    }
  }

  while (i < segs.length) {
    const seg = segs[i]!

    if (seg.linkHref) {
      closeDownTo({})
      const labelParts: TextInline[] = []
      const href = seg.linkHref
      while (i < segs.length && segs[i]!.linkHref === href) {
        const s = segs[i]!
        labelParts.push({
          type: "text",
          text: s.text,
          bold: s.bold || undefined,
          italic: s.italic || undefined,
          code: s.code || undefined,
          strikethrough: s.strikethrough || undefined,
        })
        i += 1
      }
      const label = plainTextFromInlines(labelParts)
      out += `[${escapeText(label)}](${href})`
      continue
    }

    if (seg.code) {
      closeDownTo({
        strikethrough: seg.strikethrough,
        bold: seg.bold,
        italic: seg.italic,
      })
      openUpTo({
        strikethrough: seg.strikethrough,
        bold: seg.bold,
        italic: seg.italic,
      })
      out += serializeInlineCode(seg.text)
      i += 1
      continue
    }

    const target = {
      strikethrough: seg.strikethrough,
      bold: seg.bold,
      italic: seg.italic,
    }
    closeDownTo(target)
    openUpTo(target)
    out += escapeText(seg.text)
    i += 1
  }

  closeDownTo({})
  return out
}

function serializeBlock(block: BlockNode): string {
  switch (block.type) {
    case "paragraph":
      return serializeInlines(block.children)
    case "heading":
      return `${"#".repeat(block.level)} ${serializeInlines(block.children)}`
    case "blockquote":
      return `> ${serializeInlines(block.children)}`
    case "code_block": {
      const lang = block.language ?? ""
      const fence = "`".repeat(codeBlockFenceLength(block.value))
      return `${fence}${lang}\n${block.value}\n${fence}`
    }
    case "divider":
      return "---"
    case "bullet_list":
      return block.items
        .map((item) => `- ${serializeInlines(item.children)}`)
        .join("\n")
    case "ordered_list":
      return block.items
        .map((item, index) => `${index + 1}. ${serializeInlines(item.children)}`)
        .join("\n")
    case "task_list":
      return block.items
        .map((item) => {
          const box = item.checked ? "[x]" : "[ ]"
          return `- ${box} ${serializeInlines(item.children)}`
        })
        .join("\n")
    case "raw":
      return block.markdown
  }
}

/**
 * Serialize an editor AST to canonical markdown.
 * Blocks are separated by one blank line. Bullets use `-`. Ordered lists use `1.` style renumbered from 1.
 */
export function serializeMarkdown(doc: EditorDoc): string {
  if (!doc.blocks.length) return "\n"
  const parts = doc.blocks.map(serializeBlock)
  const body = parts.join("\n\n")
  return body.endsWith("\n") ? body : `${body}\n`
}

import {
  collapsedSelection,
  createBulletList,
  createCodeBlock,
  createDivider,
  createHeading,
  createOrderedList,
  createParagraph,
  createTaskList,
  createText,
  emptyDoc,
  hasMark,
  isInlineBlock,
  isListBlock,
  marksEqual,
  normalizeSelection,
  pathEquals,
  plainTextFromInlines,
  selectionIsCollapsed,
  withMark,
  type BlockNode,
  type EditorDoc,
  type EditorPath,
  type EditorPoint,
  type EditorSelection,
  type EditorState,
  type InlineNode,
  type ListItemNode,
  type MarkType,
  type TaskItemNode,
  type TextInline,
} from "./ast"
import { sanitizeHref } from "./url"

export type BlockTypeName =
  | "paragraph"
  | "heading"
  | "blockquote"
  | "bullet_list"
  | "ordered_list"
  | "task_list"
  | "code_block"
  | "divider"

export type SetBlockTypeAttrs = {
  level?: 1 | 2 | 3
}

function cloneDoc(doc: EditorDoc): EditorDoc {
  return structuredClone(doc)
}

function mergeTextNodes(nodes: InlineNode[]): InlineNode[] {
  const out: InlineNode[] = []
  for (const node of nodes) {
    if (node.type === "link") {
      out.push({
        type: "link",
        href: node.href,
        children: mergeTextNodes(node.children) as TextInline[],
      })
      continue
    }
    const last = out[out.length - 1]
    if (last && last.type === "text" && marksEqual(last, node)) {
      last.text += node.text
    } else {
      out.push({ ...node })
    }
  }
  return out.length ? out : [createText("")]
}

function flattenInlineSegments(
  nodes: readonly InlineNode[]
): Array<{ text: string; marks: TextInline; linkHref?: string }> {
  const segs: Array<{ text: string; marks: TextInline; linkHref?: string }> = []
  for (const node of nodes) {
    if (node.type === "link") {
      for (const child of node.children) {
        segs.push({ text: child.text, marks: child, linkHref: node.href })
      }
    } else {
      segs.push({ text: node.text, marks: node })
    }
  }
  return segs
}

function rebuildInlines(
  segs: Array<{ text: string; marks: TextInline; linkHref?: string }>
): InlineNode[] {
  const nodes: InlineNode[] = []
  for (const seg of segs) {
    if (!seg.text && segs.length > 1) continue
    const text = createText(seg.text, {
      bold: seg.marks.bold,
      italic: seg.marks.italic,
      code: seg.marks.code,
      strikethrough: seg.marks.strikethrough,
    })
    if (seg.linkHref) {
      const last = nodes[nodes.length - 1]
      if (last && last.type === "link" && last.href === seg.linkHref) {
        last.children = mergeTextNodes([...last.children, text]) as TextInline[]
      } else {
        nodes.push({ type: "link", href: seg.linkHref, children: [text] })
      }
    } else {
      nodes.push(text)
    }
  }
  return mergeTextNodes(nodes)
}

function getBlock(doc: EditorDoc, path: EditorPath): BlockNode | null {
  const index = path[0]
  if (index === undefined || index < 0 || index >= doc.blocks.length) return null
  return doc.blocks[index]!
}

function getInlineChildren(
  doc: EditorDoc,
  path: EditorPath
): InlineNode[] | null {
  const block = getBlock(doc, path)
  if (!block) return null
  if (isInlineBlock(block)) return block.children
  if (isListBlock(block)) {
    const itemIndex = path[1]
    if (itemIndex === undefined) return null
    const item = block.items[itemIndex]
    if (!item) return null
    return item.children
  }
  return null
}

function setInlineChildren(
  doc: EditorDoc,
  path: EditorPath,
  children: InlineNode[]
): EditorDoc {
  const next = cloneDoc(doc)
  const block = getBlock(next, path)
  if (!block) return doc
  const merged = mergeTextNodes(children)
  if (isInlineBlock(block)) {
    block.children = merged
    return next
  }
  if (isListBlock(block)) {
    const itemIndex = path[1]
    if (itemIndex === undefined) return doc
    const item = block.items[itemIndex]
    if (!item) return doc
    item.children = merged
    return next
  }
  return doc
}

function contentLength(doc: EditorDoc, path: EditorPath): number {
  const block = getBlock(doc, path)
  if (!block) return 0
  if (block.type === "code_block") return block.value.length
  const children = getInlineChildren(doc, path)
  return children ? plainTextFromInlines(children).length : 0
}

function defaultPathForBlock(doc: EditorDoc, blockIndex: number): EditorPath {
  const block = doc.blocks[blockIndex]
  if (!block) return [0]
  if (isListBlock(block)) return [blockIndex, 0]
  return [blockIndex]
}

function sameEditableContainer(a: EditorPath, b: EditorPath): boolean {
  if (a[0] !== b[0]) return false
  const blockPathLen = a.length
  // List items require matching item index.
  if (blockPathLen >= 2 || b.length >= 2) {
    return a[1] === b[1] && a.length === b.length
  }
  return true
}

/**
 * Toggle an inline mark over the current selection.
 * Contract: when the selection spans more than one editable container
 * (different blocks or list items), this is a no-op and returns the input state.
 */
export function toggleMark(
  state: EditorState,
  mark: MarkType
): EditorState {
  const { start, end, isCollapsed } = normalizeSelection(state.selection)
  if (!sameEditableContainer(start.path, end.path)) return state
  if (getBlock(state.doc, start.path)?.type === "code_block") return state
  if (getBlock(state.doc, start.path)?.type === "raw") return state
  if (getBlock(state.doc, start.path)?.type === "divider") return state

  const children = getInlineChildren(state.doc, start.path)
  if (!children) return state

  const segs = flattenInlineSegments(children)
  const plain = segs.map((s) => s.text).join("")
  const from = Math.max(0, Math.min(start.offset, plain.length))
  const to = Math.max(from, Math.min(end.offset, plain.length))

  if (isCollapsed) {
    // Caret toggles are applied by wrapping an empty typed mark run:
    // insert a zero-width run only when there is adjacent marked text to flip.
    // Wave 1: caret toggle is a no-op without a range.
    return state
  }

  let allHave = true
  let offset = 0
  for (const seg of segs) {
    const segEnd = offset + seg.text.length
    const overlapFrom = Math.max(from, offset)
    const overlapTo = Math.min(to, segEnd)
    if (overlapFrom < overlapTo) {
      if (!hasMark(seg.marks, mark)) allHave = false
    }
    offset = segEnd
  }
  const nextOn = !allHave

  const nextSegs: typeof segs = []
  offset = 0
  for (const seg of segs) {
    const segEnd = offset + seg.text.length
    const overlapFrom = Math.max(from, offset)
    const overlapTo = Math.min(to, segEnd)
    if (overlapFrom >= overlapTo) {
      nextSegs.push(seg)
    } else {
      const localFrom = overlapFrom - offset
      const localTo = overlapTo - offset
      if (localFrom > 0) {
        nextSegs.push({
          text: seg.text.slice(0, localFrom),
          marks: seg.marks,
          linkHref: seg.linkHref,
        })
      }
      nextSegs.push({
        text: seg.text.slice(localFrom, localTo),
        marks: withMark(seg.marks, mark, nextOn),
        linkHref: seg.linkHref,
      })
      if (localTo < seg.text.length) {
        nextSegs.push({
          text: seg.text.slice(localTo),
          marks: seg.marks,
          linkHref: seg.linkHref,
        })
      }
    }
    offset = segEnd
  }

  const doc = setInlineChildren(state.doc, start.path, rebuildInlines(nextSegs))
  return {
    doc,
    selection: {
      anchor: { path: [...start.path], offset: from },
      focus: { path: [...end.path], offset: to },
    },
  }
}

export function setLink(state: EditorState, href: string): EditorState {
  const safe = sanitizeHref(href)
  if (!safe) return state
  const { start, end, isCollapsed } = normalizeSelection(state.selection)
  if (!sameEditableContainer(start.path, end.path) || isCollapsed) return state
  const children = getInlineChildren(state.doc, start.path)
  if (!children) return state

  const segs = flattenInlineSegments(children)
  const plain = segs.map((s) => s.text).join("")
  const from = Math.max(0, Math.min(start.offset, plain.length))
  const to = Math.max(from, Math.min(end.offset, plain.length))
  if (from === to) return state

  const nextSegs: typeof segs = []
  let offset = 0
  for (const seg of segs) {
    const segEnd = offset + seg.text.length
    const overlapFrom = Math.max(from, offset)
    const overlapTo = Math.min(to, segEnd)
    if (overlapFrom >= overlapTo) {
      nextSegs.push(seg)
    } else {
      const localFrom = overlapFrom - offset
      const localTo = overlapTo - offset
      if (localFrom > 0) {
        nextSegs.push({
          text: seg.text.slice(0, localFrom),
          marks: seg.marks,
          linkHref: seg.linkHref,
        })
      }
      nextSegs.push({
        text: seg.text.slice(localFrom, localTo),
        marks: seg.marks,
        linkHref: safe,
      })
      if (localTo < seg.text.length) {
        nextSegs.push({
          text: seg.text.slice(localTo),
          marks: seg.marks,
          linkHref: seg.linkHref,
        })
      }
    }
    offset = segEnd
  }

  return {
    doc: setInlineChildren(state.doc, start.path, rebuildInlines(nextSegs)),
    selection: {
      anchor: { path: [...start.path], offset: from },
      focus: { path: [...end.path], offset: to },
    },
  }
}

export function unsetLink(state: EditorState): EditorState {
  const { start, end, isCollapsed } = normalizeSelection(state.selection)
  if (!sameEditableContainer(start.path, end.path) || isCollapsed) return state
  const children = getInlineChildren(state.doc, start.path)
  if (!children) return state
  const segs = flattenInlineSegments(children)
  const plain = segs.map((s) => s.text).join("")
  const from = Math.max(0, Math.min(start.offset, plain.length))
  const to = Math.max(from, Math.min(end.offset, plain.length))
  const nextSegs = segs.map((seg, index, arr) => {
    void index
    void arr
    return seg
  })
  let offset = 0
  const rebuilt: typeof segs = []
  for (const seg of nextSegs) {
    const segEnd = offset + seg.text.length
    const overlapFrom = Math.max(from, offset)
    const overlapTo = Math.min(to, segEnd)
    if (overlapFrom >= overlapTo) {
      rebuilt.push(seg)
    } else {
      const localFrom = overlapFrom - offset
      const localTo = overlapTo - offset
      if (localFrom > 0) {
        rebuilt.push({
          text: seg.text.slice(0, localFrom),
          marks: seg.marks,
          linkHref: seg.linkHref,
        })
      }
      rebuilt.push({
        text: seg.text.slice(localFrom, localTo),
        marks: seg.marks,
      })
      if (localTo < seg.text.length) {
        rebuilt.push({
          text: seg.text.slice(localTo),
          marks: seg.marks,
          linkHref: seg.linkHref,
        })
      }
    }
    offset = segEnd
  }
  return {
    doc: setInlineChildren(state.doc, start.path, rebuildInlines(rebuilt)),
    selection: state.selection,
  }
}

function inlinesFromBlock(block: BlockNode): InlineNode[] {
  if (isInlineBlock(block)) return block.children
  if (isListBlock(block)) {
    return block.items[0]?.children.slice() ?? [createText("")]
  }
  if (block.type === "code_block") return [createText(block.value)]
  return [createText("")]
}

export function setBlockType(
  state: EditorState,
  type: BlockTypeName,
  attrs: SetBlockTypeAttrs = {}
): EditorState {
  const { start } = normalizeSelection(state.selection)
  const blockIndex = start.path[0]
  if (blockIndex === undefined) return state
  const block = state.doc.blocks[blockIndex]
  if (!block || block.type === "raw") return state

  const children = inlinesFromBlock(block)
  let nextBlock: BlockNode
  switch (type) {
    case "paragraph":
      nextBlock = createParagraph(children)
      break
    case "heading":
      nextBlock = createHeading(attrs.level ?? 1, children)
      break
    case "blockquote":
      nextBlock = { type: "blockquote", children }
      break
    case "bullet_list":
      nextBlock = createBulletList([
        { type: "list_item", children },
      ])
      break
    case "ordered_list":
      nextBlock = createOrderedList([
        { type: "list_item", children },
      ])
      break
    case "task_list":
      nextBlock = createTaskList([
        { type: "task_item", checked: false, children },
      ])
      break
    case "code_block":
      nextBlock = createCodeBlock(plainTextFromInlines(children))
      break
    case "divider":
      nextBlock = createDivider()
      break
  }

  const doc = cloneDoc(state.doc)
  doc.blocks[blockIndex] = nextBlock
  const path = defaultPathForBlock(doc, blockIndex)
  const offset = Math.min(start.offset, contentLength(doc, path))
  return { doc, selection: collapsedSelection(path, offset) }
}

export function insertBlock(
  state: EditorState,
  block: BlockNode,
  position: "before" | "after" = "after"
): EditorState {
  const { start } = normalizeSelection(state.selection)
  const index = start.path[0] ?? 0
  const doc = cloneDoc(state.doc)
  const at = position === "before" ? index : index + 1
  doc.blocks.splice(at, 0, structuredClone(block))
  const path = defaultPathForBlock(doc, at)
  return { doc, selection: collapsedSelection(path, 0) }
}

export function insertText(state: EditorState, text: string): EditorState {
  if (!text) return state
  let next = state
  if (!selectionIsCollapsed(state.selection)) {
    next = deleteSelection(state)
  }
  const { start } = normalizeSelection(next.selection)
  const block = getBlock(next.doc, start.path)
  if (!block || block.type === "raw" || block.type === "divider") return next

  if (block.type === "code_block") {
    const doc = cloneDoc(next.doc)
    const code = doc.blocks[start.path[0]!] as typeof block
    const offset = Math.max(0, Math.min(start.offset, code.value.length))
    code.value = code.value.slice(0, offset) + text + code.value.slice(offset)
    return {
      doc,
      selection: collapsedSelection(start.path, offset + text.length),
    }
  }

  const children = getInlineChildren(next.doc, start.path)
  if (!children) return next
  const segs = flattenInlineSegments(children)
  const plain = segs.map((s) => s.text).join("")
  const offset = Math.max(0, Math.min(start.offset, plain.length))

  // Inherit marks from the left neighbor.
  let inherit: TextInline = createText("")
  let linkHref: string | undefined
  let seen = 0
  for (const seg of segs) {
    if (seen + seg.text.length >= offset && offset > seen) {
      inherit = seg.marks
      linkHref = seg.linkHref
      break
    }
    if (seen + seg.text.length === offset) {
      inherit = seg.marks
      linkHref = seg.linkHref
    }
    seen += seg.text.length
  }

  const nextSegs: typeof segs = []
  seen = 0
  let inserted = false
  if (segs.length === 0 || plain.length === 0) {
    nextSegs.push({ text, marks: inherit, linkHref })
    inserted = true
  } else {
    for (const seg of segs) {
      const segEnd = seen + seg.text.length
      if (!inserted && offset <= segEnd) {
        const local = offset - seen
        if (local > 0) {
          nextSegs.push({
            text: seg.text.slice(0, local),
            marks: seg.marks,
            linkHref: seg.linkHref,
          })
        }
        nextSegs.push({ text, marks: inherit, linkHref })
        if (local < seg.text.length) {
          nextSegs.push({
            text: seg.text.slice(local),
            marks: seg.marks,
            linkHref: seg.linkHref,
          })
        }
        inserted = true
      } else {
        nextSegs.push(seg)
      }
      seen = segEnd
    }
    if (!inserted) nextSegs.push({ text, marks: inherit, linkHref })
  }

  return {
    doc: setInlineChildren(next.doc, start.path, rebuildInlines(nextSegs)),
    selection: collapsedSelection(start.path, offset + text.length),
  }
}

export function deleteSelection(state: EditorState): EditorState {
  const { start, end, isCollapsed } = normalizeSelection(state.selection)
  if (isCollapsed) return state
  if (!sameEditableContainer(start.path, end.path)) {
    // Multi-block delete collapses to deleting within the start container to the end,
    // then removes intervening blocks. Keep wave 1 simple: no-op across containers.
    return state
  }

  const block = getBlock(state.doc, start.path)
  if (!block || block.type === "raw" || block.type === "divider") return state

  if (block.type === "code_block") {
    const doc = cloneDoc(state.doc)
    const code = doc.blocks[start.path[0]!] as typeof block
    const from = Math.max(0, Math.min(start.offset, code.value.length))
    const to = Math.max(from, Math.min(end.offset, code.value.length))
    code.value = code.value.slice(0, from) + code.value.slice(to)
    return { doc, selection: collapsedSelection(start.path, from) }
  }

  const children = getInlineChildren(state.doc, start.path)
  if (!children) return state
  const segs = flattenInlineSegments(children)
  const from = start.offset
  const to = end.offset
  const nextSegs: typeof segs = []
  let offset = 0
  for (const seg of segs) {
    const segEnd = offset + seg.text.length
    const keepStart = Math.min(segEnd, Math.max(offset, from))
    const keepEnd = Math.max(offset, Math.min(segEnd, to))
    // Keep text outside [from, to)
    if (offset < from) {
      nextSegs.push({
        text: seg.text.slice(0, Math.min(seg.text.length, from - offset)),
        marks: seg.marks,
        linkHref: seg.linkHref,
      })
    }
    if (segEnd > to) {
      nextSegs.push({
        text: seg.text.slice(Math.max(0, to - offset)),
        marks: seg.marks,
        linkHref: seg.linkHref,
      })
    }
    void keepStart
    void keepEnd
    offset = segEnd
  }

  return {
    doc: setInlineChildren(state.doc, start.path, rebuildInlines(nextSegs)),
    selection: collapsedSelection(start.path, from),
  }
}

export function deleteBackward(state: EditorState): EditorState {
  if (!selectionIsCollapsed(state.selection)) return deleteSelection(state)
  const { start } = normalizeSelection(state.selection)
  if (start.offset > 0) {
    return deleteSelection({
      doc: state.doc,
      selection: {
        anchor: { path: [...start.path], offset: start.offset - 1 },
        focus: { path: [...start.path], offset: start.offset },
      },
    })
  }
  return mergeBlocks(state)
}

/**
 * Split the current block at the caret (Enter).
 */
export function splitBlock(state: EditorState): EditorState {
  let next = state
  if (!selectionIsCollapsed(state.selection)) next = deleteSelection(state)
  const { start } = normalizeSelection(next.selection)
  const blockIndex = start.path[0]
  if (blockIndex === undefined) return next
  const block = next.doc.blocks[blockIndex]
  if (!block || block.type === "raw" || block.type === "divider") return next

  if (block.type === "code_block") {
    return insertText(next, "\n")
  }

  if (isListBlock(block)) {
    const itemIndex = start.path[1] ?? 0
    const item = block.items[itemIndex]
    if (!item) return next
    const text = plainTextFromInlines(item.children)
    if (text === "" && block.items.length > 1) {
      // Empty item exits the list into a paragraph after.
      const doc = cloneDoc(next.doc)
      const list = doc.blocks[blockIndex] as typeof block
      list.items.splice(itemIndex, 1)
      if (list.items.length === 0) {
        doc.blocks[blockIndex] = createParagraph()
        return {
          doc,
          selection: collapsedSelection([blockIndex], 0),
        }
      }
      const insertAt = blockIndex + 1
      doc.blocks.splice(insertAt, 0, createParagraph())
      return {
        doc,
        selection: collapsedSelection([insertAt], 0),
      }
    }

    const left = sliceInlines(item.children, 0, start.offset)
    const right = sliceInlines(item.children, start.offset, text.length)
    const doc = cloneDoc(next.doc)
    const list = doc.blocks[blockIndex] as typeof block
    if (list.type === "task_list") {
      const task = list.items[itemIndex] as TaskItemNode
      task.children = left
      list.items.splice(itemIndex + 1, 0, {
        type: "task_item",
        checked: false,
        children: right,
      })
    } else {
      const li = list.items[itemIndex] as ListItemNode
      li.children = left
      list.items.splice(itemIndex + 1, 0, {
        type: "list_item",
        children: right,
      })
    }
    return {
      doc,
      selection: collapsedSelection([blockIndex, itemIndex + 1], 0),
    }
  }

  if (!isInlineBlock(block)) return next
  const text = plainTextFromInlines(block.children)
  const left = sliceInlines(block.children, 0, start.offset)
  const right = sliceInlines(block.children, start.offset, text.length)
  const doc = cloneDoc(next.doc)
  const current = doc.blocks[blockIndex]!
  if (current.type === "heading") {
    current.children = left
    doc.blocks.splice(blockIndex + 1, 0, createParagraph(right))
  } else if (current.type === "blockquote") {
    current.children = left
    doc.blocks.splice(blockIndex + 1, 0, {
      type: "blockquote",
      children: right,
    })
  } else if (current.type === "paragraph") {
    current.children = left
    doc.blocks.splice(blockIndex + 1, 0, createParagraph(right))
  } else {
    return next
  }
  return {
    doc,
    selection: collapsedSelection([blockIndex + 1], 0),
  }
}

function sliceInlines(
  nodes: readonly InlineNode[],
  from: number,
  to: number
): InlineNode[] {
  const segs = flattenInlineSegments(nodes)
  const next: typeof segs = []
  let offset = 0
  for (const seg of segs) {
    const segEnd = offset + seg.text.length
    const a = Math.max(from, offset)
    const b = Math.min(to, segEnd)
    if (a < b) {
      next.push({
        text: seg.text.slice(a - offset, b - offset),
        marks: seg.marks,
        linkHref: seg.linkHref,
      })
    }
    offset = segEnd
  }
  return rebuildInlines(next)
}

/**
 * Merge the current block into the previous block when the caret is at offset 0.
 */
export function mergeBlocks(state: EditorState): EditorState {
  if (!selectionIsCollapsed(state.selection)) return state
  const { start } = normalizeSelection(state.selection)
  if (start.offset !== 0) return state

  const blockIndex = start.path[0]
  if (blockIndex === undefined || blockIndex === 0) return state
  const doc = cloneDoc(state.doc)
  const current = doc.blocks[blockIndex]!
  const previous = doc.blocks[blockIndex - 1]!

  if (isListBlock(current) && start.path[1] !== undefined && start.path[1] > 0) {
    const itemIndex = start.path[1]
    const list = current
    const item = list.items[itemIndex]!
    const prevItem = list.items[itemIndex - 1]!
    const prevLen = plainTextFromInlines(prevItem.children).length
    prevItem.children = mergeTextNodes([
      ...prevItem.children,
      ...item.children,
    ])
    list.items.splice(itemIndex, 1)
    return {
      doc,
      selection: collapsedSelection([blockIndex, itemIndex - 1], prevLen),
    }
  }

  if (previous.type === "raw" || current.type === "raw") return state
  if (previous.type === "divider") {
    doc.blocks.splice(blockIndex - 1, 1)
    return {
      doc,
      selection: collapsedSelection(defaultPathForBlock(doc, blockIndex - 1), 0),
    }
  }

  if (previous.type === "code_block" && current.type === "code_block") {
    const prevLen = previous.value.length
    previous.value = previous.value + (previous.value && current.value ? "\n" : "") + current.value
    doc.blocks.splice(blockIndex, 1)
    return { doc, selection: collapsedSelection([blockIndex - 1], prevLen) }
  }

  if (isListBlock(previous) && isInlineBlock(current)) {
    const lastIndex = previous.items.length - 1
    const last = previous.items[lastIndex]!
    const prevLen = plainTextFromInlines(last.children).length
    last.children = mergeTextNodes([...last.children, ...current.children])
    doc.blocks.splice(blockIndex, 1)
    return {
      doc,
      selection: collapsedSelection([blockIndex - 1, lastIndex], prevLen),
    }
  }

  if (isInlineBlock(previous) && isInlineBlock(current)) {
    const prevLen = plainTextFromInlines(previous.children).length
    previous.children = mergeTextNodes([
      ...previous.children,
      ...current.children,
    ])
    doc.blocks.splice(blockIndex, 1)
    return {
      doc,
      selection: collapsedSelection([blockIndex - 1], prevLen),
    }
  }

  if (isInlineBlock(previous) && isListBlock(current) && (start.path[1] ?? 0) === 0) {
    const first = current.items[0]!
    const prevLen = plainTextFromInlines(previous.children).length
    previous.children = mergeTextNodes([
      ...previous.children,
      ...first.children,
    ])
    current.items.shift()
    if (current.items.length === 0) doc.blocks.splice(blockIndex, 1)
    return {
      doc,
      selection: collapsedSelection([blockIndex - 1], prevLen),
    }
  }

  return state
}

export function indentListItem(state: EditorState): EditorState {
  // Wave 1 lists are flat; indent is a no-op reserved for nested lists later.
  return state
}

export function outdentListItem(state: EditorState): EditorState {
  const { start } = normalizeSelection(state.selection)
  const blockIndex = start.path[0]
  if (blockIndex === undefined) return state
  const block = state.doc.blocks[blockIndex]
  if (!block || !isListBlock(block)) return state
  const itemIndex = start.path[1] ?? 0
  const item = block.items[itemIndex]
  if (!item) return state

  const doc = cloneDoc(state.doc)
  const list = doc.blocks[blockIndex] as typeof block
  list.items.splice(itemIndex, 1)
  const paragraph = createParagraph(item.children)
  if (list.items.length === 0) {
    doc.blocks[blockIndex] = paragraph
    return { doc, selection: collapsedSelection([blockIndex], start.offset) }
  }
  doc.blocks.splice(blockIndex + 1, 0, paragraph)
  return {
    doc,
    selection: collapsedSelection([blockIndex + 1], start.offset),
  }
}

export function toggleTaskChecked(
  state: EditorState,
  path?: EditorPath
): EditorState {
  const target = path ?? normalizeSelection(state.selection).start.path
  const blockIndex = target[0]
  const itemIndex = target[1]
  if (blockIndex === undefined || itemIndex === undefined) return state
  const doc = cloneDoc(state.doc)
  const block = doc.blocks[blockIndex]
  if (!block || block.type !== "task_list") return state
  const item = block.items[itemIndex]
  if (!item) return state
  item.checked = !item.checked
  return { doc, selection: state.selection }
}

export function insertDivider(state: EditorState): EditorState {
  const split = splitBlock(state)
  const { start } = normalizeSelection(split.selection)
  const index = start.path[0] ?? 0
  const doc = cloneDoc(split.doc)
  doc.blocks.splice(index, 0, createDivider())
  return {
    doc,
    selection: collapsedSelection([index + 1], 0),
  }
}

export function pasteMarkdownBlocks(
  state: EditorState,
  blocks: BlockNode[]
): EditorState {
  let next = state
  if (!selectionIsCollapsed(state.selection)) next = deleteSelection(state)
  if (blocks.length === 0) return next
  if (blocks.length === 1 && isInlineBlock(blocks[0]!)) {
    return insertText(next, plainTextFromInlines(blocks[0]!.children))
  }

  const { start } = normalizeSelection(next.selection)
  const blockIndex = start.path[0] ?? 0
  const doc = cloneDoc(next.doc)
  const current = doc.blocks[blockIndex]
  const atStart =
    start.offset === 0 &&
    current &&
    isInlineBlock(current) &&
    plainTextFromInlines(current.children) === ""

  if (atStart) {
    doc.blocks.splice(blockIndex, 1, ...blocks.map((b) => structuredClone(b)))
  } else {
    doc.blocks.splice(
      blockIndex + 1,
      0,
      ...blocks.map((b) => structuredClone(b))
    )
  }
  const focusIndex = atStart
    ? blockIndex + blocks.length - 1
    : blockIndex + blocks.length
  const path = defaultPathForBlock(doc, focusIndex)
  return {
    doc,
    selection: collapsedSelection(path, contentLength(doc, path)),
  }
}

export function replaceDoc(markdownDoc: EditorDoc, selection?: EditorSelection): EditorState {
  const doc = markdownDoc.blocks.length ? markdownDoc : emptyDoc()
  return {
    doc,
    selection:
      selection ??
      collapsedSelection(defaultPathForBlock(doc, 0), 0),
  }
}

export function pointAt(
  path: EditorPath,
  offset: number
): EditorPoint {
  return { path: [...path], offset }
}

export function selectionAround(
  path: EditorPath,
  from: number,
  to: number
): EditorSelection {
  return {
    anchor: pointAt(path, from),
    focus: pointAt(path, to),
  }
}

export function isMarkActive(
  state: EditorState,
  mark: MarkType
): boolean {
  const { start, end, isCollapsed } = normalizeSelection(state.selection)
  if (!sameEditableContainer(start.path, end.path)) return false
  const children = getInlineChildren(state.doc, start.path)
  if (!children) return false
  const segs = flattenInlineSegments(children)
  const plain = segs.map((s) => s.text).join("")
  const from = isCollapsed
    ? Math.max(0, start.offset - 1)
    : start.offset
  const to = isCollapsed ? start.offset : end.offset
  if (plain.length === 0) return false
  let offset = 0
  let saw = false
  for (const seg of segs) {
    const segEnd = offset + seg.text.length
    const a = Math.max(from, offset)
    const b = Math.min(to === from ? to + 1 : to, segEnd)
    if (a < b) {
      saw = true
      if (!hasMark(seg.marks, mark)) return false
    }
    offset = segEnd
  }
  return saw
}

export function activeBlockType(
  state: EditorState
): { type: BlockTypeName; level?: 1 | 2 | 3 } | null {
  const { start } = normalizeSelection(state.selection)
  const block = getBlock(state.doc, start.path)
  if (!block || block.type === "raw") return null
  if (block.type === "heading") return { type: "heading", level: block.level }
  return { type: block.type as BlockTypeName }
}

export function pathsEqual(a: EditorPath, b: EditorPath): boolean {
  return pathEquals(a, b)
}

import {
  normalizeSelection,
  plainTextFromInlines,
  type EditorState,
} from "./ast"
import { setBlockType, type BlockTypeName } from "./transforms"

export type InputRuleResult = {
  state: EditorState
} | null

type Rule = {
  match: RegExp
  type: BlockTypeName
  level?: 1 | 2 | 3
}

const SPACE_RULES: Rule[] = [
  { match: /^###$/, type: "heading", level: 3 },
  { match: /^##$/, type: "heading", level: 2 },
  { match: /^#$/, type: "heading", level: 1 },
  { match: /^>$/, type: "blockquote" },
  { match: /^-$/, type: "bullet_list" },
  { match: /^\*$/, type: "bullet_list" },
  { match: /^\+$/, type: "bullet_list" },
  { match: /^1\.$/, type: "ordered_list" },
  { match: /^```$/, type: "code_block" },
  { match: /^---$/, type: "divider" },
  { match: /^\*\*\*$/, type: "divider" },
  { match: /^[-*+] \[[ xX]\]$/, type: "task_list" },
]

/**
 * Match markdown autoformat prefixes at the start of the current paragraph.
 * Invoke after inserting a trailing space (or newline for a fence-only paragraph).
 */
export function matchInputRule(
  state: EditorState,
  insertedText: string
): InputRuleResult {
  if (insertedText !== " " && insertedText !== "\n") return null
  const { start, isCollapsed } = normalizeSelection(state.selection)
  if (!isCollapsed) return null

  const blockIndex = start.path[0]
  if (blockIndex === undefined) return null
  const block = state.doc.blocks[blockIndex]
  if (!block || block.type !== "paragraph") return null
  if (start.path.length !== 1) return null

  const plain = plainTextFromInlines(block.children)

  if (insertedText === "\n") {
    if (plain === "```") {
      const without = deletePrefix(state, plain.length)
      return { state: setBlockType(without, "code_block") }
    }
    return null
  }

  if (start.offset < 1) return null
  const before = plain.slice(0, start.offset)
  if (!before.endsWith(" ")) return null
  const token = before.slice(0, -1)
  if (token.includes("\n")) return null

  for (const rule of SPACE_RULES) {
    if (!rule.match.test(token)) continue
    const without = deletePrefix(state, token.length + 1)
    return {
      state: setBlockType(without, rule.type, { level: rule.level }),
    }
  }

  return null
}

function deletePrefix(state: EditorState, count: number): EditorState {
  if (count <= 0) return state
  const { start } = normalizeSelection(state.selection)
  const blockIndex = start.path[0]!
  const block = state.doc.blocks[blockIndex]
  if (!block || block.type !== "paragraph") return state
  const plain = plainTextFromInlines(block.children)
  const from = Math.max(0, start.offset - count)
  const to = start.offset
  const nextText = plain.slice(0, from) + plain.slice(to)
  const doc = structuredClone(state.doc)
  const paragraph = doc.blocks[blockIndex]!
  if (paragraph.type !== "paragraph") return state
  paragraph.children = [{ type: "text", text: nextText }]
  return {
    doc,
    selection: {
      anchor: { path: [blockIndex], offset: from },
      focus: { path: [blockIndex], offset: from },
    },
  }
}

/** Apply an input rule after text insertion. Returns the transformed state or the original. */
export function applyInputRule(
  state: EditorState,
  insertedText: string
): EditorState {
  const matched = matchInputRule(state, insertedText)
  return matched ? matched.state : state
}

const BLOCKED_SCHEMES = /^(javascript|data|vbscript):/i

/**
 * Validate a link href for the editor model.
 * Allows http, https, mailto, and relative paths. Rejects javascript and data schemes.
 */
export function isSafeHref(href: string): boolean {
  const value = href.trim()
  if (!value) return false
  if (BLOCKED_SCHEMES.test(value)) return false
  if (/^[\s\S]*[\u0000-\u001F\u007F]/.test(value)) return false

  const schemeMatch = /^([a-zA-Z][a-zA-Z0-9+.-]*):/.exec(value)
  if (!schemeMatch) {
    // Relative, hash, or protocol-relative-looking without scheme token.
    if (value.startsWith("//")) return false
    return true
  }

  const scheme = schemeMatch[1]!.toLowerCase()
  return scheme === "http" || scheme === "https" || scheme === "mailto"
}

/** Return a safe href, or null when the value must not be stored or rendered as a link. */
export function sanitizeHref(href: string): string | null {
  const trimmed = href.trim()
  if (!isSafeHref(trimmed)) return null
  return trimmed
}
